import{_ as a,H as e,f as l,i as r}from"./chunks/framework.eFU6Tutu.js";const c=JSON.parse('{"title":"Выращивание перца на подоконнике: полное руководство","description":"","frontmatter":{},"headers":[],"relativePath":"care/peppers.md","filePath":"care/peppers.md"}'),i={name:"care/peppers.md"};function o(n,t,s,h,d,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="выращивание-перца-на-подоконнике-полное-руководство" tabindex="-1">Выращивание перца на подоконнике: полное руководство <a class="header-anchor" href="#выращивание-перца-на-подоконнике-полное-руководство" aria-label="Permalink to &quot;Выращивание перца на подоконнике: полное руководство&quot;">​</a></h1><p>Выращивание перца в комнатных условиях — дело более хлопотное, чем зелени, но очень благодарное. Красивый, плодоносящий куст того стоит. Главное — помнить, что перец теплолюбив и плохо переносит пикировку.</p><h2 id="выбор-сорта" tabindex="-1">Выбор сорта <a class="header-anchor" href="#выбор-сорта" aria-label="Permalink to &quot;Выбор сорта&quot;">​</a></h2><p>Это ключевой момент. Для подоконника подходят только <strong>раннеспелые, самоопыляемые, карликовые или компактные</strong> сорта, специально выведенные для ограниченного объёма грунта. Ищите на упаковке пометки «комнатный», «балконный», «карликовый». Помните про раздельное выращивание сладких и острых перцев.</p><h2 id="посев-семян-и-выращивание-рассады" tabindex="-1">Посев семян и выращивание рассады <a class="header-anchor" href="#посев-семян-и-выращивание-рассады" aria-label="Permalink to &quot;Посев семян и выращивание рассады&quot;">​</a></h2><h3 id="сроки" tabindex="-1">Сроки <a class="header-anchor" href="#сроки" aria-label="Permalink to &quot;Сроки&quot;">​</a></h3><p>Сеять можно в любое время года, но оптимально с конца января до начала марта. При зимнем посеве потребуется интенсивная досветка.</p><h3 id="подготовка-семян-и-почвы" tabindex="-1">Подготовка семян и почвы <a class="header-anchor" href="#подготовка-семян-и-почвы" aria-label="Permalink to &quot;Подготовка семян и почвы&quot;">​</a></h3><ol><li><strong>Семена:</strong> Замочите на 10-15 минут в слабом растворе марганцовки для дезинфекции. Затем промойте. Для ускорения прорастания замочите в тёплой воде на сутки или прорастите во влажной салфетке при температуре +24-28°C до появления корешков (10-12 дней).</li><li><strong>Почва:</strong> Грунт должен быть рыхлым, питательным, нейтральной кислотности. Можно использовать готовый грунт для рассады или смешать торф, перегной и дерновую землю (2:1:1). Обязательно продезинфицируйте почву (пропарьте или пролейте марганцовкой).</li></ol><h3 id="посев" tabindex="-1">Посев <a class="header-anchor" href="#посев" aria-label="Permalink to &quot;Посев&quot;">​</a></h3><p>Перец плохо переносит пикировку, поэтому лучше сеять семена сразу в индивидуальные ёмкости (стаканчики 100-200 мл). Заглубите семена на 1-1.5 см, накройте плёнкой для создания парникового эффекта и поставьте в тёплое место (+22-26°C).</p><h3 id="уход-за-рассадои" tabindex="-1">Уход за рассадой <a class="header-anchor" href="#уход-за-рассадои" aria-label="Permalink to &quot;Уход за рассадой&quot;">​</a></h3><ol><li><strong>Свет:</strong> Как только появятся всходы (через 5-15 дней), плёнку снимите и поставьте сеянцы на самое светлое место. В первые 7-10 дней для предотвращения вытягивания полезно снизить температуру до +16-18°C. Затем верните к +20-25°C.</li><li><strong>Досветка:</strong> С октября по март обязательна досветка фитолампой до 12-14 часов в сутки.</li><li><strong>Полив:</strong> Умеренный, по мере подсыхания верхнего слоя почвы, тёплой отстоянной водой. Переувлажнение ведёт к «чёрной ножке».</li><li><strong>Подкормка:</strong> Первая подкормка — через 2-3 недели после всходов (комплексное удобрение с преобладанием фосфора и калия, азота — минимум).</li></ol><h2 id="пересадка-на-постоянное-место" tabindex="-1">Пересадка на постоянное место <a class="header-anchor" href="#пересадка-на-постоянное-место" aria-label="Permalink to &quot;Пересадка на постоянное место&quot;">​</a></h2><p>По мере роста перец нужно аккуратно переваливать (не нарушая земляной ком) в горшки большего объёма:</p><ul><li><strong>Первая перевалка (фаза 3-4 настоящих листьев):</strong> в горшок 0.8-1 литр.</li><li><strong>Вторая перевалка (перед началом цветения, когда корни освоят предыдущий объём):</strong> в постоянный горшок объёмом <strong>3-5 литров</strong>. На дно обязателен дренаж (керамзит).</li></ul><h2 id="уход-за-взрослым-растением" tabindex="-1">Уход за взрослым растением <a class="header-anchor" href="#уход-за-взрослым-растением" aria-label="Permalink to &quot;Уход за взрослым растением&quot;">​</a></h2><h3 id="освещение-и-температура" tabindex="-1">Освещение и температура <a class="header-anchor" href="#освещение-и-температура" aria-label="Permalink to &quot;Освещение и температура&quot;">​</a></h3><ul><li><strong>Свет:</strong> 12-16 часов яркого света. Лучшее место — южный или юго-восточный подоконник. Зимой досветка обязательна.</li><li><strong>Температура:</strong> Оптимально +22-26°C. Не любит резких перепадов и сквозняков. Корни не должны переохлаждаться (можно утеплить подоконник пенопластом).</li></ul><h3 id="полив-и-влажность" tabindex="-1">Полив и влажность <a class="header-anchor" href="#полив-и-влажность" aria-label="Permalink to &quot;Полив и влажность&quot;">​</a></h3><ul><li><strong>Полив:</strong> Регулярный, по мере просыхания грунта на 1-1.5 см в глубину. Тёплой отстоянной водой. Растение плохо переносит как пересушку, так и залив.</li><li><strong>Влажность:</strong> Предпочитает умеренную влажность. Полезно опрыскивать листья, особенно в отопительный сезон.</li></ul><h3 id="формирование-куста" tabindex="-1">Формирование куста <a class="header-anchor" href="#формирование-куста" aria-label="Permalink to &quot;Формирование куста&quot;">​</a></h3><ul><li><strong>Острый и декоративный перец:</strong> Формировки не требуют, кустятся сами.</li><li><strong>Сладкий перец:</strong> Требует формирования. Обычно ведут куст в 2-3 стебля. Первый цветок (коронный) часто удаляют для лучшего развития куста. Пасынки и листья до первой развилки удаляют.</li></ul><h3 id="опыление" tabindex="-1">Опыление <a class="header-anchor" href="#опыление" aria-label="Permalink to &quot;Опыление&quot;">​</a></h3><p>Перец — самоопыляемое растение. Для лучшего завязывания плодов в период цветения можно слегка встряхивать куст или аккуратно проводить кисточкой по цветкам.</p><h3 id="подкормка" tabindex="-1">Подкормка <a class="header-anchor" href="#подкормка" aria-label="Permalink to &quot;Подкормка&quot;">​</a></h3><p>Подкармливайте регулярно, раз в 10-14 дней, начиная с фазы бутонизации. Используйте специальные удобрения для томатов/перцев с повышенным содержанием калия и фосфора (особенно важны в период плодоношения). Органические подкормки (настой золы, биогумус) хорошо чередовать с минеральными.</p><h2 id="проблемы-при-выращивании" tabindex="-1">Проблемы при выращивании <a class="header-anchor" href="#проблемы-при-выращивании" aria-label="Permalink to &quot;Проблемы при выращивании&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Проблема</th><th style="text-align:left;">Причина</th><th style="text-align:left;">Решение</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Вытягивание стеблей, бледные листья</strong></td><td style="text-align:left;">Недостаток света</td><td style="text-align:left;">Переставить на светлое окно, досветка</td></tr><tr><td style="text-align:left;"><strong>Опадают бутоны и завязи</strong></td><td style="text-align:left;">Недостаток света, перелив или пересушка, холод, нехватка питания</td><td style="text-align:left;">Обеспечить 12-16 часов света и стабильный полив, убрать от сквозняков, подкормить калийно-фосфорным удобрением</td></tr><tr><td style="text-align:left;"><strong>Пожелтение и скручивание листьев</strong></td><td style="text-align:left;">Недостаток питания, слишком тесный горшок, холодная вода</td><td style="text-align:left;">Пересадить, подкормить комплексным удобрением, поливать только тёплой водой</td></tr><tr><td style="text-align:left;"><strong>Мелкие, невкусные плоды</strong></td><td style="text-align:left;">Недостаток света или питания</td><td style="text-align:left;">Увеличить световой день, провести подкормку удобрением для плодоношения</td></tr><tr><td style="text-align:left;"><strong>Тля, паутинный клещ</strong> (редко)</td><td style="text-align:left;">Сухой воздух, заражённый грунт</td><td style="text-align:left;">Повысить влажность, обработать раствором зелёного мыла или биопрепаратами (Фитоверм)</td></tr></tbody></table><h2 id="сбор-урожая-и-уход-за-растением" tabindex="-1">Сбор урожая и уход за растением <a class="header-anchor" href="#сбор-урожая-и-уход-за-растением" aria-label="Permalink to &quot;Сбор урожая и уход за растением&quot;">​</a></h2><ul><li><strong>Сбор:</strong> Перцы срезают или срывают (осторожно, стебли хрупкие) по мере созревания. Сбор урожая стимулирует образование новых завязей.</li><li><strong>Многолетнее выращивание:</strong> После основного плодоношения куст можно обрезать, оставив 10-15 см, пересадить в свежий грунт. В благоприятных условиях он даст второй урожай через 2-3 месяца.</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://azbyka.ru/garden/vyrashhivanie-perczev-v-kvartire/" target="_blank" rel="noreferrer">Азбука садовода — Выращивание перцев в квартире</a></li><li><a href="https://7dach.ru/OrganicMix/perec-na-podokonnike-master-klass-po-vyraschivaniyu-i-uhodu-281486.html" target="_blank" rel="noreferrer">7 дач — Перец на подоконнике: мастер-класс</a></li></ul><h2 id="навигация-по-разделу" tabindex="-1">Навигация по разделу <a class="header-anchor" href="#навигация-по-разделу" aria-label="Permalink to &quot;Навигация по разделу&quot;">​</a></h2><ul><li><a href="/plants/peppers.html">Статья о перцах (сорта, описание, польза)</a></li><li><a href="/recipes/peppers.html">Рецепты с перцами</a></li></ul>',35)])])}const f=a(i,[["render",o]]);export{c as __pageData,f as default};
